import { useState, useEffect } from "react";
import { Brain, TrendingUp, TrendingDown, Activity } from "lucide-react";

const AIPrediction = ({ company, isLoading }) => {
  const [prediction, setPrediction] = useState(null);
  const [confidence, setConfidence] = useState(0);

  useEffect(() => {
    if (company && !isLoading) {
      setPrediction(null);
      setConfidence(0);

      const timer = setTimeout(() => {
        const currentPrice = Number(company.current_price ?? company.currentPrice);
        const change = Number(company.change ?? 0);

        const trend = change >= 0 ? 1 : -1;
        const volatility = Math.random() * 0.04; // max ±4%
        const predictedPrice = currentPrice * (1 + trend * volatility);

        const diff = predictedPrice - currentPrice;
        const diffPercent = (diff / currentPrice) * 100;

        setPrediction({
          price: predictedPrice,
          change: diff,
          changePercent: diffPercent,
        });
        setConfidence(Math.floor(Math.random() * 15) + 80); 
      }, 2500);

      return () => clearTimeout(timer);
    }
  }, [company, isLoading]);

  return (
    <div className="bg-gradient-to-br from-indigo-600 via-purple-600 to-blue-700 rounded-2xl p-4 sm:p-6 text-white shadow-2xl w-full max-w-md mx-auto sm:max-w-lg">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-4 gap-3 sm:gap-0">
        <div className="flex items-center gap-3 w-full sm:w-auto">
          <div className="p-2 sm:p-3 bg-white/10 rounded-xl backdrop-blur">
            <Brain size={20} className="text-white sm:w-6 sm:h-6" />
          </div>
          <div className="flex-1 sm:flex-none">
            <h3 className="text-base sm:text-lg font-bold">AI Market Prediction</h3>
            <p className="text-indigo-200 text-xs sm:text-sm">Next trading day forecast</p>
          </div>
        </div>
        {confidence > 0 && (
          <div className="text-left sm:text-right w-full sm:w-auto">
            <div className="text-xl sm:text-2xl font-bold text-green-300">{confidence}%</div>
            <div className="text-xs text-indigo-200">Confidence</div>
          </div>
        )}
      </div>

      {!prediction || isLoading ? (
        <div className="flex flex-col sm:flex-row items-center justify-center py-6 sm:py-8 gap-3 sm:gap-0">
          <div className="relative">
            <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-full border-4 border-white/20 border-t-white animate-spin"></div>
            <div className="absolute inset-0 w-10 h-10 sm:w-12 sm:h-12 rounded-full border-4 border-transparent border-r-purple-300 animate-ping"></div>
          </div>
          <div className="ml-0 sm:ml-4 text-center sm:text-left">
            <div className="font-semibold text-sm sm:text-base">Analyzing market patterns...</div>
            <div className="text-indigo-200 text-xs sm:text-sm">Processing technical indicators</div>
          </div>
        </div>
      ) : (
        <div className="space-y-4">
          <div className="flex flex-col sm:flex-row items-start sm:items-end justify-between gap-3 sm:gap-0">
            <div className="w-full sm:w-auto">
              <div className="text-2xl sm:text-3xl font-bold">₹{prediction.price.toFixed(2)}</div>
              <div
                className={`flex items-center gap-1 mt-1 ${
                  prediction.change >= 0 ? "text-green-300" : "text-red-300"
                } flex-wrap`}
              >
                {prediction.change >= 0 ? <TrendingUp size={14} className="sm:w-4 sm:h-4" /> : <TrendingDown size={14} className="sm:w-4 sm:h-4" />}
                <span className="font-semibold text-sm sm:text-base">
                  {prediction.change >= 0 ? "+" : ""}₹{Math.abs(prediction.change).toFixed(2)}
                </span>
                <span className="text-xs sm:text-sm">
                  ({prediction.change >= 0 ? "+" : ""}
                  {prediction.changePercent.toFixed(2)}%)
                </span>
              </div>
            </div>
            <div className="text-left sm:text-right">
              <Activity className="w-6 h-6 sm:w-8 sm:h-8 text-purple-300 opacity-75" />
            </div>
          </div>

          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center pt-4 border-t border-white/20 gap-2 sm:gap-0">
            <span className="text-indigo-200 text-xs sm:text-sm">Based on technical analysis</span>
            <div className="flex gap-1">
              {[...Array(5)].map((_, i) => (
                <div
                  key={i}
                  className={`w-1.5 h-1.5 sm:w-2 sm:h-2 rounded-full ${
                    i < Math.floor(confidence / 20) ? "bg-green-400" : "bg-white/20"
                  }`}
                ></div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};



export default Demo;
